        setUpDb("testDeleteExpired");

        EmployeeDbAccess target = new EmployeeDbAccess();
        SqlResultSet actual = target.deleteExpired();

        // トランザクションをコミット
        commitTransactions();

        // 引数：期待値を格納したシート名, 実際の値
